import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a factor?", a: "A factor is a number that divides another number evenly with no remainder. For example, 3 is a factor of 12 because 12 divided by 3 equals 4." },
  { q: "How do you find all factors of a number?", a: "Test divisors from 1 up to the square root of the number. Each divisor that divides evenly gives a factor pair." },
  { q: "What is a prime number?", a: "A prime number is a positive integer greater than 1 with exactly two factors: 1 and itself." },
  { q: "What is the difference between factors and multiples?", a: "Factors divide into a number evenly. Multiples are results of multiplying that number by whole numbers." },
  { q: "What are factor pairs?", a: "Factor pairs are two numbers that multiply together to make the original number, such as 3 and 8 for 24." },
];

export default function FactorCalculator() {
  const [value, setValue] = useState(84);
  const result = useMemo(() => {
    const n = Math.abs(Math.trunc(value));
    if (n < 1) return null;
    const factors: number[] = [];
    const pairs: string[] = [];
    for (let i = 1; i * i <= n; i++) if (n % i === 0) { factors.push(i); if (i !== n / i) factors.push(n / i); pairs.push(`${i} x ${n / i}`); }
    factors.sort((a, b) => a - b);
    const prime = n > 1 && factors.length === 2;
    return { n, factors, pairs, prime };
  }, [value]);

  return (
    <>
      <SEOHead title="Free Factor Calculator Online - Find All Factors of Any Number Instantly | CalcHive" description="Free online factor calculator. Find all factors of any positive integer instantly with step by step solution. Identifies prime numbers too. 100% free for students, no signup required." canonical="/factor-calculator" keywords="free factor calculator, factors of a number calculator free, find all factors free online, factor finder calculator free, prime factor calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Factor Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free factor calculator to find all factors free online and identify prime numbers.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="factor-value" className="text-sm font-semibold text-foreground block mb-2">Positive integer</label>
          <input id="factor-value" type="number" min="1" inputMode="numeric" value={value} onChange={(event) => setValue(Number(event.target.value))} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          {result ? <motion.div key={value} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-8">
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.prime ? "Prime Number" : "Total Factors"}</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-factor">{result.factors.length}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Factors</p><p className="text-sm font-extrabold text-foreground break-words">{result.factors.join(", ")}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Factor pairs</p><p className="text-sm font-extrabold text-foreground break-words">{result.pairs.join("; ")}</p></div></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">Test whole-number divisors from 1 through {Math.floor(Math.sqrt(result.n))}. Every divisor with no remainder creates a factor pair. {result.n} is {result.prime ? "prime because it has only 1 and itself as factors." : "not prime because it has more than two factors."}</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-6">Enter a positive integer.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Find All Factors of Any Number for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a positive integer and this factors of a number calculator free lists every factor and factor pair.</p><h2 className="text-2xl font-bold text-foreground">How to Tell if a Number is Prime</h2><p className="text-muted-foreground leading-relaxed">If the number has exactly two factors, 1 and itself, it is prime. Otherwise, it is composite.</p><h2 className="text-2xl font-bold text-foreground">Free Number Factor Finder for Math Students</h2><p className="text-muted-foreground leading-relaxed">Use this factor finder calculator free for divisibility, fractions, GCF, LCM, and number theory practice.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/factor-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


